// Recoit { runId, criteria, ingestUrl, ingestSecret }. Construit l'URL de l'API SRP.
// Params confirmes sur une vraie URL atHome : tr, ptypes, srf_min/max, bedrooms_min, old_build, loc.
const b = $json.body || $json;
const c = b.criteria || {};
const params = new URLSearchParams();
params.set('tr', 'buy');
params.set('ptypes', c.propertyType === 'house' ? 'house' : 'flat,4,43');
if (c.surfaceMin) params.set('srf_min', String(c.surfaceMin));
if (c.surfaceMax) params.set('srf_max', String(c.surfaceMax));
if (c.priceMin) params.set('price_min', String(c.priceMin));
if (c.priceMax) params.set('price_max', String(c.priceMax));
if (c.bedroomsMin) params.set('bedrooms_min', String(c.bedroomsMin));
params.set('old_build', 'true');
if (c.loc) params.set('loc', c.loc);
params.set('page', '1');
const url = 'https://www.athome.lu/srp/?' + params.toString();
return [{ json: { runId: b.runId, ingestUrl: b.ingestUrl, ingestSecret: b.ingestSecret, criteria: c, searchUrl: url } }];

// PARSE + FILTRE LISTE — teste sur de vraies donnees atHome (12/12 extraites).
const ctx = $('Construit l\'URL SRP').first().json;
const c = ctx.criteria || {};
const html = $json.data || $json.body || '';
function extractState(html) {
  const mi = html.indexOf('window.__INITIAL_STATE__');
  if (mi === -1) throw new Error('INITIAL_STATE introuvable (page bloquee ?)');
  let i = html.indexOf('=', mi) + 1; while (/\s/.test(html[i])) i++;
  const s = i; let depth = 0, inStr = false, esc = false;
  for (; i < html.length; i++) { const ch = html[i];
    if (esc) { esc = false; continue; } if (ch === '\\') { esc = true; continue; }
    if (ch === '"') { inStr = !inStr; continue; } if (inStr) continue;
    if (ch === '{') depth++; else if (ch === '}') { depth--; if (depth === 0) { i++; break; } } }
  return JSON.parse(html.slice(s, i).replace(/:\s*undefined/g, ': null'));
}
const state = extractState(html);
const list = (state.search && state.search.list) || [];
const listings = (state.search && state.search.listings) || [];
const permById = {}; for (const x of listings) permById[x.id] = x.permalink && x.permalink.fr;
const kw = (c.keywords || []).map(k => k.toLowerCase());
const out = [];
for (const a of list) {
  if (a.isSoldProperty) continue;
  if (a.isNewBuild) continue;
  const desc = (a.description || '').toLowerCase();
  if (kw.length && !kw.some(k => desc.includes(k))) continue;
  out.push({ runId: ctx.runId, ingestUrl: ctx.ingestUrl, ingestSecret: ctx.ingestSecret,
    cpeClasses: c.cpeClasses || [], id: String(a.id), price: a.price, surface: a.propertySurface,
    commune: (a.geo && a.geo.cityName) || '', rooms: a.bedroomsCount, title: (a.title || '').toString(),
    url: 'https://www.athome.lu' + (permById[a.id] || ('/vente/appartement/luxembourg/id-' + a.id + '.html')) });
}
return out.map(json => ({ json }));

// EXTRAIT CPE depuis la fiche detail + filtre cpeClasses. Regex testee sur le vrai rendu atHome.
const meta = $('Parse + filtre liste').item.json;
const html = $json.data || $json.body || '';
const norm = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
const m = norm.match(/Classe\s+[\u00e9e]nerg[\u00e9e]?tique[^A-Za-z]{0,40}?([A-I])\b/i);
const cpe = m ? m[1].toUpperCase() : null;
const classes = meta.cpeClasses || [];
const keep = !classes.length || (cpe && classes.includes(cpe));
return [{ json: { ...meta, cpe, _keep: keep } }];

// AGREGE les biens retenus en un seul payload pour l'app.
const all = $input.all().map(i => i.json).filter(x => x._keep);
const first = $('Construit l\'URL SRP').first().json;
const listings = all.map(({ runId, ingestUrl, ingestSecret, cpeClasses, _keep, ...rest }) => rest);
return [{ json: { ingestUrl: first.ingestUrl, runId: first.runId, ingestSecret: first.ingestSecret, listings } }];
